<!-- SECTION 8: DOCUMENTS REQUIRED -->
<section class="content-section" id="documents-section">
    <div class="content-container">
        <div class="text-content">
            <h2 class="section-title">Documents Required for Object Clause Change in Mumbai</h2>
            <div class="content-text">
                
                <ul>
                    <li><strong>Company CIN and PAN:</strong> For MCA portal login and form pre-fill</li>
                    <li><strong>Current MOA:</strong> Existing Memorandum showing current Clause III (Object Clause)</li>
                    <li><strong>Current AOA:</strong> Articles of Association (for reference and alteration if needed)</li>
                    <li><strong>Board Resolution:</strong> Certified copy approving object clause amendment and EGM convening</li>
                    <li><strong>EGM Notice with Explanatory Statement:</strong> Section 101 notice with Section 102 statement detailing reason for amendment</li>
                    <li><strong>Special Resolution:</strong> Certified copy passed at EGM (75% majority)</li>
                    <li><strong>EGM Minutes:</strong> Signed minutes recording proceedings, voting details, and declaration</li>
                    <li><strong>Altered MOA:</strong> Updated Clause III reflecting amended objects</li>
                    <li><strong>DSC of Director:</strong> Valid Class 2/3 Digital Signature Certificate</li>
                    <li><strong>Newspaper Publications (public companies):</strong> Copies of English and Marathi newspaper notices</li>
